@Module
@InstallIn(SingletonComponent::class)
object AppModule {

    private const val BASE_URL = "https://your-fastapi-backend.onrender.com/"

    @Provides
    @Singleton
    fun provideOkHttpClient(): OkHttpClient {
        return OkHttpClient.Builder()
            .connectTimeout(30, TimeUnit.SECONDS)
            .readTimeout(60, TimeUnit.SECONDS)
            .writeTimeout(30, TimeUnit.SECONDS)
            .addInterceptor(HttpLoggingInterceptor().apply {
                level = HttpLoggingInterceptor.Level.BODY
            })
            .build()
    }

    @Provides
    @Singleton
    fun provideRetrofit(okHttpClient: OkHttpClient): Retrofit {
        return Retrofit.Builder()
            .baseUrl(BASE_URL)
            .client(okHttpClient)
            .addConverterFactory(GsonConverterFactory.create())
            .build()
    }

    @Provides
    @Singleton
    fun providePalmistryApiService(retrofit: Retrofit): PalmistryApiService {
        return retrofit.create(PalmistryApiService::class.java)
    }

    @Provides
    @Singleton
    fun providePalmistryDatabase(@ApplicationContext context: Context): PalmistryDatabase {
        return PalmistryDatabase.getInstance(context)
    }

    @Provides
    @Singleton
    fun provideReadingDao(db: PalmistryDatabase): ReadingDao {
        return db.readingDao()
    }
}

package com.example.palmistry.data.repository

import com.example.palmistry.data.local.ReadingDao
import com.example.palmistry.data.model.EncryptedRequest
import com.example.palmistry.data.model.ReadingEntity
import com.example.palmistry.network.PalmistryApiService
import com.example.palmistry.security.EncryptionUtil
import com.google.gson.Gson
import kotlinx.coroutines.flow.Flow
import javax.crypto.SecretKey
import javax.inject.Inject
import javax.inject.Singleton

/**
 * Repository: Single source of truth between ViewModel, Network and Local DB.
 * Handles encryption before sending, decryption after receiving.
 */
@Singleton
class PalmistryRepository @Inject constructor(
    private val apiService: PalmistryApiService,
    private val readingDao: ReadingDao,
    private val encryptionUtil: EncryptionUtil
) {
    private val gson = Gson()

    /**
     * Send palm metadata to backend and get AI reading.
     * @param question  The user's palmistry question
     * @param metadata  The palm line JSON from TFLite
     * @param secretKey AES-256 key for payload encryption
     */
    suspend fun generateReading(
        question: String,
        metadata: Map<String, Any>,
        secretKey: SecretKey
    ): Result<String> {
        return try {
            // Build payload
            val payload = mapOf("question" to question, "metadata" to metadata)
            val jsonPayload = gson.toJson(payload)

            // Encrypt payload
            val encryptedPayload = encryptionUtil.encrypt(jsonPayload, secretKey)
            val request = EncryptedRequest(payload = encryptedPayload)

            // Send to backend
            val response = apiService.generateReading(request)
            if (response.isSuccessful) {
                val body = response.body()!!
                // Decrypt response
                val decryptedJson = encryptionUtil.decrypt(body.payload, secretKey)
                val resultMap = gson.fromJson(decryptedJson, Map::class.java)
                Result.success(resultMap["reading"] as String)
            } else {
                Result.failure(Exception("Server error: ${response.code()}"))
            }
        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    /** Save reading to local encrypted Room DB */
    suspend fun saveReadingLocally(reading: ReadingEntity) {
        readingDao.insertReading(reading)
    }

    /** Get all past readings as a reactive Flow */
    fun getAllReadings(): Flow<List<ReadingEntity>> = readingDao.getAllReadings()

    /** Delete a specific reading */
    suspend fun deleteReading(id: Int) = readingDao.deleteReading(id)
}

package com.example.palmistry.ui.viewmodel

import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.example.palmistry.data.model.ReadingEntity
import com.example.palmistry.data.repository.PalmistryRepository
import com.example.palmistry.security.EncryptionUtil
import dagger.hilt.android.lifecycle.HiltViewModel
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.launch
import javax.inject.Inject

sealed class ReadingUiState {
    object Idle : ReadingUiState()
    object Loading : ReadingUiState()
    data class Success(val reading: String) : ReadingUiState()
    data class Error(val message: String) : ReadingUiState()
}

@HiltViewModel
class PalmistryViewModel @Inject constructor(
    private val repository: PalmistryRepository,
    private val encryptionUtil: EncryptionUtil
) : ViewModel() {

    private val _uiState = MutableStateFlow<ReadingUiState>(ReadingUiState.Idle)
    val uiState: StateFlow<ReadingUiState> = _uiState.asStateFlow()

    // Generate a new AES key per session (in production: load from Keystore)
    private val sessionKey = encryptionUtil.generateKey()

    val readingHistory = repository.getAllReadings()

    /**
     * Called when the palm is captured and TFLite returns the metadata JSON.
     */
    fun generateReading(palmJson: String, userQuestion: String = "Mera haath padhiye") {
        _uiState.value = ReadingUiState.Loading
        viewModelScope.launch {
            val metadata = mapOf("palm_json" to palmJson)
            val result = repository.generateReading(userQuestion, metadata, sessionKey)
            result.fold(
                onSuccess = { reading ->
                    _uiState.value = ReadingUiState.Success(reading)
                    // Save to local encrypted DB
                    repository.saveReadingLocally(
                        ReadingEntity(
                            palmMetadataJson = palmJson,
                            readingResult = reading,
                            lifeLineScore = 0f,
                            heartLineScore = 0f,
                            headLineScore = 0f,
                            fateLineScore = 0f,
                            confidenceScore = 0f
                        )
                    )
                },
                onFailure = { e ->
                    _uiState.value = ReadingUiState.Error(e.message ?: "Unknown error")
                }
            )
        }
    }

    fun resetState() {
        _uiState.value = ReadingUiState.Idle
    }

    fun deleteReading(id: Int) {
        viewModelScope.launch { repository.deleteReading(id) }
    }
}

